sql:
SELECT stock_symbol 
FROM stocks 
WHERE company_name = 'Apple Inc.';

SELECT al.access_time, COUNT(DISTINCT al.user_id) AS total_unique_users
FROM user_access_logs al
GROUP BY al.access_time;

SELECT old_price, new_price 
FROM price_history 
WHERE stock_id = 1;

SELECT COUNT(DISTINCT stock_symbol) 
FROM stocks 
WHERE company_name = 'Apple Inc.';

SELECT stock_id
FROM daily_stock_data
WHERE close_price > (SELECT AVG(close_price) FROM daily_stock_data);

SELECT data_date, open_price, close_price
FROM daily_stock_data
WHERE stock_id = 1;
